/**
 * Customized from:
 * https://github.com/remarkjs/remark-math/tree/main/packages/remark-math
 */
import { codes } from "micromark-util-symbol/codes";

import { mathBracket } from "./math-bracket-block";
import { mathBracketInline } from "./math-bracket-inline";
import { mathFlow } from "./math-flow";
import { mathParenthesisInline } from "./math-parenthesis-inline";
import { mathText } from "./math-text";

import type { Extension } from "micromark-util-types";

/**
 * Add support for parsing math in markdown.
 *
 * Function that can be called to get a syntax extension for micromark (passed
 * in `extensions`).
 *
 * @param {Options} [options]
 *   Configuration (optional).
 * @returns {Extension}
 *   Syntax extension for micromark (passed in `extensions`).
 */
export function math(): Extension {
  return {
    /**
     * Block level parsing supported:
     * `\[...\]`
     * `$$...$$`
     */
    flow: { [codes.dollarSign]: mathFlow, [codes.backslash]: mathBracket },
    /**
     * Inline level parsing supported:
     * `\(...\)`
     * `\[...\]`
     * `$$...$$`
     */
    text: {
      [codes.dollarSign]: mathText(),
      [codes.backslash]: [mathParenthesisInline(), mathBracketInline()],
    },
  };
}
